css: /* Glitch Text Effect CSS */\n.glitch-text {
  position: relative;
  display: inline-block;
}
.glitch-text::after {
  content: attr(data-text);
  position: absolute;
  clip: rect(1px 1px 1px 1px); /* Create a clipping rectangle */
  clip-path: polygon(0 0, 0 100%, 100% 100%, 100% 0);
  transform: translate(-50%, -50%) scale(1); /* Initial scales to 1 */
}
.glitch-text:hover::after {
  animation: glitch 0.5s infinite;
}

@keyframes glitch {
  0% {
    clip-path: polygon(0 0, 0 100%, 100% 100%, 100% 0);
    transform: translate(-50%, -50%) scale(1);
  }
  25% {
    clip-path: polygon(0 0, 100% 0, 100% 100%, 50% 50%);
    transform: translate(-50%, -50%) scale(1.1);
  }
  50% {
    clip-path: polygon(0 0, 100% 0, 100% 100%, 100% 50%);
    transform: translate(-50%, -50%) scale(0.9);
  }
  75% {
    clip-path: polygon(0 0, 100% 0, 100% 100%, 50% 50%);
    transform: translate(-50%, -50%) scale(1.05);
  }
  100% {
    clip-path: polygon(0 0, 0 100%, 100% 100%, 100% 0);
    transform: translate(-50%, -50%) scale(1);
  }
}

js: /* Glitch Text Effect JavaScript */\ndocument.addEventListener('DOMContentLoaded', function() {
  const glitchText = document.querySelector('.glitch-text');
  glitchText.addEventListener('mouseover', function() {
    const text = glitchText.getAttribute('data-text');
    glitchText.innerHTML = '';
    const span = document.createElement('span');
    span.textContent = text;
    glitchText.appendChild(span);
  });
});
